class SemanticNode:
    def __init__(self, name, attributes=None):
        self.name = name
        self.attributes = attributes or {}
        self.relations = {}

    def add_relation(self, relation_type, node):
        if relation_type not in self.relations:
            self.relations[relation_type] = []
        self.relations[relation_type].append(node)

    def get_relations(self, relation_type):
        return self.relations.get(relation_type, [])

class SemanticNetwork:
    def __init__(self):
        self.nodes = {}

    def add_node(self, name, attributes=None):
        node = SemanticNode(name, attributes)
        self.nodes[name] = node
        return node

    def add_relation(self, from_name, relation_type, to_name):
        if from_name in self.nodes and to_name in self.nodes:
            self.nodes[from_name].add_relation(relation_type, self.nodes[to_name])

    def query(self, node_name, relation_type):
        if node_name in self.nodes:
            return [n.name for n in self.nodes[node_name].get_relations(relation_type)]
        return []

# Create semantic network
network = SemanticNetwork()

# Add nodes (entities)
network.add_node("Animal", {"alive": True})
network.add_node("Bird", {"can_fly": True})
network.add_node("Penguin", {"can_fly": False})
network.add_node("Tweety", {"color": "yellow"})

# Add relations (is-a relationships)
network.add_relation("Bird", "is-a", "Animal")
network.add_relation("Penguin", "is-a", "Bird")
network.add_relation("Tweety", "is-a", "Bird")

# Add attribute relations
network.add_relation("Tweety", "has-color", "Yellow")

# Query the network
print("Birds are:", network.query("Bird", "is-a"))
print("Tweety is a:", network.query("Tweety", "is-a"))
print("Penguin is a:", network.query("Penguin", "is-a"))

class Frame:
    def __init__(self, name, parent=None):
        self.name = name
        self.parent = parent
        self.slots = {}
        self.own_slots = {}

    def set_slot(self, slot_name, value):
        self.own_slots[slot_name] = value
        self.slots[slot_name] = value

    def get_slot(self, slot_name):
        if slot_name in self.own_slots:
            return self.own_slots[slot_name]
        elif self.parent:
            return self.parent.get_slot(slot_name)
        return None

    def get_all_slots(self):
        if self.parent:
            parent_slots = self.parent.get_all_slots()
        else:
            parent_slots = {}
        return {**parent_slots, **self.own_slots}

# Create frame hierarchy
animal_frame = Frame("Animal")
animal_frame.set_slot("can_move", True)
animal_frame.set_slot("has_nervous_system", True)
animal_frame.set_slot("needs_food", True)

bird_frame = Frame("Bird", parent=animal_frame)
bird_frame.set_slot("can_fly", True)
bird_frame.set_slot("has_feathers", True)
bird_frame.set_slot("lays_eggs", True)

penguin_frame = Frame("Penguin", parent=bird_frame)
penguin_frame.set_slot("can_fly", False)
penguin_frame.set_slot("can_swim", True)
penguin_frame.set_slot("habitat", "Antarctica")

# Test inheritance
print(f"Penguin can fly: {penguin_frame.get_slot('can_fly')}")
print(f"Penguin has feathers: {penguin_frame.get_slot('has_feathers')}")
print(f"Penguin needs food: {penguin_frame.get_slot('needs_food')}")
print(f"Penguin habitat: {penguin_frame.get_slot('habitat')}")

print("\nAll Penguin slots:", penguin_frame.get_all_slots())

class Script:
    def __init__(self, name, roles, props, scenes):
        self.name = name
        self.roles = roles      # List of参与者 roles
        self.props = props       # Objects involved
        self.scenes = scenes     # Ordered list of scenes

    def execute(self, role_bindings=None):
        bindings = role_bindings or {}
        print(f"\n=== Executing Script: {self.name} ===")
        print(f"Roles: {', '.join(self.roles)}")
        print(f"Props: {', '.join(self.props)}")
        print("-" * 40)

        for i, scene in enumerate(self.scenes, 1):
            print(f"\nScene {i}: {scene['name']}")
            for action in scene['actions']:
                # Replace placeholders with bindings
                action_str = action
                for role, actor in bindings.items():
                    action_str = action_str.replace(f"[{role}]", actor)
                print(f"  → {action_str}")

# Define restaurant script
restaurant_script = Script(
    name="Restaurant",
    roles=["Customer", "Waiter", "Chef"],
    props=["Menu", "Table", "Order", "Food", "Bill", "Money"],
    scenes=[
        {
            "name": "Entering",
            "actions": [
                "[Customer] enters the restaurant",
                "[Customer] is seated at the table",
                "[Waiter] brings menu to [Customer]"
            ]
        },
        {
            "name": "Ordering",
            "actions": [
                "[Customer] reviews the menu",
                "[Customer] places order with [Waiter]",
                "[Waiter] transmits order to [Chef]"
            ]
        },
        {
            "name": "Eating",
            "actions": [
                "[Chef] prepares the food",
                "[Waiter] serves food to [Customer]",
                "[Customer] eats the food"
            ]
        },
        {
            "name": "Exiting",
            "actions": [
                "[Waiter] brings bill to [Customer]",
                "[Customer] pays the bill",
                "[Customer] leaves the restaurant"
            ]
        }
    ]
)

# Execute script with specific actors
restaurant_script.execute({
    "Customer": "John",
    "Waiter": "Mike",
    "Chef": "Chef Ramsay"
})
